<?php $title='Dashboard';require __DIR__.'/partials/header.php';?><div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Stream dashboard</h1><p class="text-secondary mb-0">Profile: <?=e($v4['server']['name'])?> · Health: <?=e($v4['health']['status'])?></p></div><span class="badge text-bg-<?= $active?'success':'secondary' ?> fs-6"><?=e($active['status']??'stopped')?></span></div><?php if($active):?><div class="card border-success mb-3"><div class="card-body"><h2 class="h5">Now streaming: <?=e($active['channel_name'])?></h2><p class="mb-2">Playlist: <?=e($active['playlist_name'])?> · Restarts: <?=e((string)$health['restart_count'])?></p><div class="d-flex gap-2"><form method="post" action="/streams/restart"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="stream_id" value="<?=e((string)$active['id'])?>"><button class="btn btn-outline-primary">Restart</button></form><form method="post" action="/streams/stop"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="stream_id" value="<?=e((string)$active['id'])?>"><button class="btn btn-danger">Stop</button></form></div></div></div><?php endif?><div class="row g-3"><?php foreach(['Health Score'=>$v4['health']['score'],'CPU Steal'=>$v4['system']['cpu_steal_percent'].'%','Encoding Speed'=>$v4['stream']['speed'].'x','Bitrate'=>$v4['stream']['bitrate'].' kbps']as$label=>$value):?><div class="col-md-3"><div class="card"><div class="card-body"><div class="text-secondary"><?=e($label)?></div><strong class="fs-4"><?=e((string)$value)?></strong></div></div></div><?php endforeach?></div><?php foreach($v4['health']['warnings']as$warning):?><div class="alert alert-warning mt-3"><?=e($warning)?></div><?php endforeach?><?php if($v4['recommendation']):?><div class="alert alert-info mt-3"><?=e($v4['recommendation'])?></div><?php endif?><?php require __DIR__.'/partials/footer.php'; ?>
